mapper.select:
/* 로그인용 사용자 조회 login.selectUser */ SELECT U.COMP_ID, C.COMP_NM, U.USER_ID, U.USER_NM, U.PASSWD, U.DEPT_ID, DP.DEPT_NM, U.JIKGUB_CD, JG.CODE_NM JIKGUB_NM, U.POS_CD, POS.CODE_NM POS_NM, U.BIRTH_DT, U.JOIN_DT, U.TEL, U.PHONE, U.EMAIL, U.IP_ADDRESS, U.IP_CHK, U.ETC, U.PW_INIT_YN, U.PW_CHANGE_DT, IFNULL(U.MAIN_PGM_ID, 'PGM1913') AS MAIN_PGM_ID, U.USER_STATUS_CD, USR_ST.CODE_NM USER_STATUS_NM, C.COMP_LANG LANG, C.COMP_LANG COMP_LANG, IF(SAI.AI_SAI_USE_YN='Y', 'Y' ,'N') AS COMP_SAI_USE_YN, IF(SAI.AI_SAI_USE_YN='Y', 'Y' ,'N') AS AI_SAI_USE_YN, CASE
WHEN (C.PW_CHANGE_CYCLE IS NULL OR C.PW_CHANGE_CYCLE = '') THEN 'N'
WHEN (IFNULL(U.PW_CHANGE_DT,'')='') THEN 'N' ELSE CASE WHEN DATEDIFF(SYSDATE(), U.PW_CHANGE_DT) > C.PW_CHANGE_CYCLE THEN 'Y' ELSE 'N' END END AS ALERT_PW_CHANGE_YN, C.PW_CHANGE_CYCLE, D.CONNECTION_ID, D.DB_ID, IF(U.USER_STATUS_CD='001', 'Y' ,'N') AS BEING_YN FROM ${dbId}.COM_USERINFO U LEFT JOIN COM_COMPINFO C ON U.COMP_ID = C.COMP_ID LEFT JOIN COM_COMP_DBINFO D ON U.COMP_ID = D.COMP_ID LEFT OUTER JOIN ( SELECT COMP_ID, IF(INSTR(SERVICE_TYPE, '10')=0, 'N', 'Y') AS AI_SAI_USE_YN FROM COM_COMPINFO_DETAIL WHERE COMP_ID = #{compId} AND CURRENT_SEQ='Y' ) SAI ON U.COMP_ID = SAI.COMP_ID LEFT OUTER JOIN COM_DEPTINFO DP ON U.COMP_ID = DP.COMP_ID AND U.DEPT_ID = DP.DEPT_ID LEFT OUTER JOIN COM_CODE JG ON U.COMP_ID = JG.COMP_ID AND JG.CODE_GRP_ID = '537' AND U.JIKGUB_CD = JG.CODE_ID LEFT OUTER JOIN COM_CODE POS ON U.COMP_ID = POS.COMP_ID AND POS.CODE_GRP_ID = '536' AND U.POS_CD = POS.CODE_ID LEFT OUTER JOIN COM_CODE USR_ST ON U.COMP_ID = USR_ST.COMP_ID AND USR_ST.CODE_GRP_ID = '538' AND U.USER_STATUS_CD = USR_ST.CODE_ID WHERE U.COMP_ID = #{compId} AND U.USER_ID = #{userId}

/* 인사평가만 서비스 하는지 여부 데이터 return login.selectIsOnlyInsa */
SELECT CASE WHEN LOCATE('03', A.SERVICE_TYPE) = 0 AND LOCATE('04', A.SERVICE_TYPE) > 0 THEN 'Y'
            ELSE 'N' END AS IS_ONLY_INSA_YN
  FROM COM_COMPINFO_DETAIL A
 WHERE A.COMP_ID = #{compId}
   AND A.CURRENT_SEQ = 'Y'

/* 로그인 사용자의 연도별 성과조직 목록 조회 login.selectUserScDeptList */
SELECT M.YEAR, M.SC_DEPT_ID
FROM V_ROLE_USER U
JOIN ORG_INSA_DEPT_MAPPING M
ON U.COMP_ID = M.COMP_ID
AND U.DEPT_ID = M.DEPT_ID
WHERE U.COMP_ID = #{compId}
AND U.USER_ID = #{userId}
ORDER BY M.YEAR

/* 서비스 사용여부 조회 login.selectServiceUseYn */
SELECT

    'Y' USE_YN
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}

mapper.update:
/* 인증시도 횟수 조회 login.updateAccessCertificationStatusData */
UPDATE COM_ACCESS_AUTH
SET LAST_OCCUR_DATETIME = NOW(),
STATUS = #{status},
FAIL_COUNT = #{failCount}
WHERE COMP_ID = #{compId}
AND USER_ID = #{userId}
AND IN_TYPE = #{inType}

mapper.delete:
/* 인증시도 횟수 조회 login.deleteAccessCertificationStatusData */
DELETE FROM COM_ACCESS_AUTH
WHERE COMP_ID = #{compId}
AND USER_ID = #{userId}
AND IN_TYPE = #{inType}

mapper.update:
/*	OTP인증일시 업데이트	login.updateOTPReqDt	*/
UPDATE COM_OTP_AUTH
SET REQ_DT=now()
WHERE COMP_ID=#{compId}
AND USER_ID=#{userId}

mapper.select:
/*	사용 가능한 토큰여부 	login.selectAvailableTokenYn	*/
SELECT CASE WHEN COUNT(1)= 0 THEN 'Y' ELSE 'N' END
FROM COM_ACCESS_CERTIFICATION_LOG
WHERE IN_TYPE = 'jwt'
AND COMP_ID = #{compId}
AND USER_ID = #{userId}
AND TOKEN = #{token}

/* 고객사별 메뉴 갯수 조회  */
SELECT COUNT(*)
FROM COM_PGM

/* 전체 관리자 확인 여부  login.selectAuth */
SELECT AUTH_GUBUN
FROM COM_ADMIN
WHERE USER_ID = #{userId}
AND AUTH_GUBUN = '01'

/* 전체 관리자 확인 여부  login.selectIpList */
SELECT ALLOW_IP
FROM COM_ACCESS_ACL
WHERE USER_ID = #{userId}

/* 전체 관리자 확인 여부 login.beforePwdList */
SELECT PASSWD
FROM COM_USERINFO_PW_CHANGE
WHERE USER_ID = #{userId}
ORDER BY SEQ DESC
LIMIT ${limit}

/* 전체 관리자 확인 여부 login.pwCnt */
SELECT PW_CNT
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}
